import os
import subprocess

def install_dependencies():
    print("Installing dependencies...")
    try:
        subprocess.check_call([ 'pip', 'install', '-r', 'requirements.txt' ])
    except Exception as e:
        print(f"Error occurred during dependency installation: {e}")

def run_tests():
    print("Running tests...")
    try:
        subprocess.check_call([ 'pytest' ])
    except Exception as e:
        print(f"Error occurred during test execution: {e}")

def package_for_deployment():
    print("Packaging for deployment...")
    try:
        os.system('python3 setup.py sdist bdist_wheel')
    except Exception as e:
        print(f"Error occurred during packaging: {e}")

if __name__ == "__main__":
    install_dependencies()
    run_tests()
    package_for_deployment()